        </span>
      );
    case 'GM':
      return (
        <span className="px-1.5 py-0.5 rounded text-[10px] font-bold bg-yellow-500/20 text-yellow-400 border border-yellow-500/30">
          GM
        </span>
      );
    case 'MODERATOR':
      return (
        <span className="px-1.5 py-0.5 rounded text-[10px] font-bold bg-blue-500/20 text-blue-400 border border-blue-500/30">
          MOD
        </span>
      );
    default:
      return null;
  }
}

function getClassColor(cls: string) {
  switch (cls) {
    case 'Warrior':
      return 'text-orange-400';
    case 'Mage':
      return 'text-blue-400';
    case 'Archer':
      return 'text-green-400';
    case 'Priest':
      return 'text-yellow-300';
    case 'Assassin':
      return 'text-purple-400';
    case 'Knight':
      return 'text-cyan-400';
    default:
      return 'text-gray-400';
  }
}

export default function ThreadDetailPage({
  params,
}: {
  params: { threadId: string };
}) {
  const [posts, setPosts] = useState<Post[]>(mockPosts);
  const [replyContent, setReplyContent] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [reactingToPostId, setReactingToPostId] = useState<string | null>(null);

  const handleReply = (e: React.FormEvent) => {
    e.preventDefault();
    if (!replyContent.trim()) return;

    setIsSubmitting(true);
    setTimeout(() => {
      const newPost: Post = {
        id: `post-${Date.now()}`,
        author: 'You',
        authorLevel: 65,
        authorClass: 'Warrior',
        authorRole: 'PLAYER',
        content: replyContent.trim(),
        createdAt: new Date().toLocaleString(),
        reactions: [],
        isEdited: false,
      };

      setPosts((prev) => [...prev, newPost]);
      setReplyContent('');
      setIsSubmitting(false);
    }, 500);
  };

  const handleReaction = (postId: string, emoji: string) => {
    setPosts((prev) =>
      prev.map((post) => {
        if (post.id !== postId) return post;

        const existingReaction = post.reactions.find((r) => r.emoji === emoji);
        if (existingReaction) {
          return {
            ...post,
            reactions: post.reactions.map((r) =>
              r.emoji === emoji
                ? {
                    ...r,
                    count: r.userReacted ? r.count - 1 : r.count + 1,
                    userReacted: !r.userReacted,
                  }
                : r
            ),
          };
        } else {
          return {
            ...post,
            reactions: [...post.reactions, { emoji, count: 1, userReacted: true }],
          };
        }
      })
    );
  };

  return (
    <div className="space-y-6">
      {/* Breadcrumb */}
      <div className="flex items-center gap-2 text-sm text-muted-foreground">
        <Link href="/community/forums" className="hover:text-primary transition-colors">
          Forums
        </Link>
        <span>/</span>
        <Link
          href={`/community/forums/${mockThread.category.toLowerCase().replace(/\s+/g, '-')}`}
          className="hover:text-primary transition-colors"
        >
          {mockThread.category}
        </Link>
        <span>/</span>
        <span className="text-white truncate">{mockThread.title}</span>
      </div>

      {/* Thread Header */}
      <div className="rounded-2xl border-2 border-primary/20 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-6">
        <div className="flex items-start justify-between gap-4 mb-4">
          <div className="flex-1">
            <h1 className="font-heading text-2xl font-bold text-white">{mockThread.title}</h1>
            <div className="flex items-center gap-2 mt-2 text-sm text-muted-foreground flex-wrap">
              <span className="text-primary font-medium">{mockThread.author}</span>
              {getRoleBadge(mockThread.authorRole)}
              <span className={`text-xs ${getClassColor(mockThread.authorClass)}`}>
                Lv.{mockThread.authorLevel} {mockThread.authorClass}
              </span>
              <span>•</span>
              <span>{mockThread.createdAt}</span>
            </div>
          </div>
          {mockThread.isLocked && (
            <div className="flex items-center gap-2 rounded-lg bg-red-500/10 border border-red-500/30 px-3 py-1.5">
              <span className="text-lg">🔒</span>
              <span className="text-xs font-medium text-red-400">Locked</span>
            </div>
          )}
        </div>

        {/* Stats */}
        <div className="flex items-center gap-6 text-sm text-muted-foreground">
          <div className="flex items-center gap-2">
            <span className="text-primary">👁️</span>
            <span>{mockThread.viewCount.toLocaleString()} views</span>
          </div>
          <div className="flex items-center gap-2">
            <span className="text-primary">💬</span>
            <span>{mockThread.replyCount} replies</span>
          </div>
        </div>
      </div>

      {/* Posts */}
      <div className="space-y-4">
        {posts.map((post, index) => (
          <div
            key={post.id}
            className="rounded-2xl border-2 border-primary/10 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5 hover:border-primary/20 transition-all duration-200"
          >
            {/* Post Header */}
            <div className="flex items-start gap-4 mb-3">
              <div className="flex-shrink-0 h-10 w-10 rounded-full bg-primary/20 flex items-center justify-center text-sm font-bold text-primary border border-primary/30">
                {post.author[0]}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 flex-wrap">
                  <span className="font-medium text-white">{post.author}</span>
                  {getRoleBadge(post.authorRole)}
                  <span className={`text-xs ${getClassColor(post.authorClass)}`}>
                    Lv.{post.authorLevel} {post.authorClass}
                  </span>
                </div>
                <div className="flex items-center gap-2 mt-1 text-xs text-muted-foreground">
                  <span>{post.createdAt}</span>
                  {post.isEdited && <span>• edited</span>}
                  <span>• #{index + 1}</span>
                </div>
              </div>
            </div>

            {/* Post Content */}
            <div className="mb-4 text-sm text-gray-300 leading-relaxed whitespace-pre-wrap break-words">
              {post.content}
            </div>

            {/* Reactions */}
            <div className="flex items-center gap-2 flex-wrap mb-3">
              {post.reactions.map((reaction) => (
                <button
                  key={reaction.emoji}
                  onClick={() => handleReaction(post.id, reaction.emoji)}
                  className={`rounded-lg px-2.5 py-1 text-xs font-ui font-medium transition-all duration-200 flex items-center gap-1 ${
                    reaction.userReacted
                      ? 'bg-primary/20 text-primary border border-primary/40'
                      : 'bg-[#111111] text-muted-foreground border border-primary/10 hover:text-white hover:border-primary/30'
                  }`}
                >
                  <span>{reaction.emoji}</span>
                  <span>{reaction.count}</span>
                </button>
              ))}
              <button
                onClick={() => setReactingToPostId(reactingToPostId === post.id ? null : post.id)}
                className="rounded-lg px-2.5 py-1 text-xs font-ui font-medium bg-[#111111] text-muted-foreground border border-primary/10 hover:text-white hover:border-primary/30 transition-all duration-200"
              >
                😊
              </button>
            </div>

            {/* Reaction Picker */}
            {reactingToPostId === post.id && (
              <div className="mb-3 flex items-center gap-2 p-2 rounded-lg bg-[#111111] border border-primary/20">
                {['👍', '❤️', '😂', '🔥', '💯', '🎉', '😢', '🤔'].map((emoji) => (
                  <button
                    key={emoji}
                    onClick={() => {
                      handleReaction(post.id, emoji);
                      setReactingToPostId(null);
                    }}
                    className="text-lg hover:scale-125 transition-transform"
                  >
                    {emoji}
                  </button>
                ))}
              </div>
            )}

            {/* Post Actions */}
            <div className="flex items-center gap-3 text-xs text-muted-foreground">
              <button className="hover:text-primary transition-colors">Reply</button>
              <button className="hover:text-primary transition-colors">Report</button>
              {post.author === 'You' && (
                <>
                  <button className="hover:text-primary transition-colors">Edit</button>
                  <button className="hover:text-red-400 transition-colors">Delete</button>
                </>
              )}
            </div>
          </div>
        ))}
      </div>

      {/* Reply Form */}
      {!mockThread.isLocked ? (
        <div className="rounded-2xl border-2 border-primary/20 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-6">
          <h2 className="font-heading text-lg font-bold text-white mb-4">Reply to Thread</h2>
          <form onSubmit={handleReply} className="space-y-4">
            <textarea
              value={replyContent}
              onChange={(e) => setReplyContent(e.target.value)}
              placeholder="Write your reply here..."
              className="w-full rounded-xl border-2 border-primary/20 bg-[#111111] px-4 py-3 text-sm text-white placeholder:text-muted-foreground focus:border-primary/50 focus:outline-none focus:ring-1 focus:ring-primary/30 resize-none min-h-[120px]"
            />
            <div className="flex items-center justify-between">
              <p className="text-xs text-muted-foreground">
                Be respectful and follow community guidelines
              </p>
              <button
                type="submit"
                disabled={isSubmitting || !replyContent.trim()}
                className="rounded-xl border-2 border-primary bg-primary/10 px-6 py-2 text-sm font-ui font-medium text-primary hover:bg-primary/20 hover:shadow-[0_0_15px_#7c3aed40] transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isSubmitting ? 'Posting...' : 'Post Reply'}
              </button>
            </div>
          </form>
        </div>
      ) : (
        <div className="rounded-2xl border-2 border-red-500/20 bg-red-500/5 backdrop-blur-[16px] p-6 text-center">
          <span className="text-2xl block mb-2">🔒</span>
          <p className="text-sm text-red-400">This thread is locked and no longer accepting replies.</p>
        </div>
      )}
    </div>
  );
}

