'use client';

import { useState } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { Button } from '@mmorpg/ui';
import {
  LayoutDashboard,
  Users,
  FileText,
  Shield,
  Activity,
  BarChart3,
  Menu,
  X,
  LogOut,
} from 'lucide-react';

interface AdminLayoutProps {
  children: React.ReactNode;
}

const navigationItems = [
  {
    label: 'Dashboard',
    href: '/admin',
    icon: LayoutDashboard,
  },
  {
    label: 'Users',
    href: '/admin/users',
    icon: Users,
  },
  {
    label: 'CMS',
    href: '/admin/cms',
    icon: FileText,
  },
  {
    label: 'Moderation',
    href: '/admin/moderation',
    icon: Shield,
  },
  {
    label: 'Monitoring',
    href: '/admin/monitoring',
    icon: Activity,
  },
  {
    label: 'Analytics',
    href: '/admin/analytics',
    icon: BarChart3,
  },
];

export function AdminLayout({ children }: AdminLayoutProps) {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const pathname = usePathname();

  const isActive = (href: string) => {
    if (href === '/admin') {
      return pathname === '/admin';
    }
    return pathname.startsWith(href);
  };

  return (
    <div className="flex h-screen bg-[#060606]">
      {/* Sidebar */}
      <aside
        className={`${
          sidebarOpen ? 'w-64' : 'w-20'
        } bg-[#111111] border-r border-[#7C3AED]/20 transition-all duration-300 flex flex-col`}
      >
        {/* Logo/Header */}
        <div className="h-16 flex items-center justify-between px-4 border-b border-[#7C3AED]/20">
          {sidebarOpen && (
            <h1 className="font-heading text-lg font-bold text-[#7C3AED]">
              ADMIN
            </h1>
          )}
          <button
            onClick={() => setSidebarOpen(!sidebarOpen)}
            className="p-2 hover:bg-[#7C3AED]/10 rounded-lg transition-colors"
          >
            {sidebarOpen ? (
              <X className="w-5 h-5" />
            ) : (
              <Menu className="w-5 h-5" />
            )}
          </button>
        </div>

        {/* Navigation */}
        <nav className="flex-1 px-3 py-6 space-y-2 overflow-y-auto">
          {navigationItems.map((item) => {
            const Icon = item.icon;
            const active = isActive(item.href);

            return (
              <Link key={item.href} href={item.href}>
                <button
                  className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all duration-200 ${
                    active
                      ? 'bg-[#7C3AED] text-white shadow-lg shadow-[#7C3AED]/50'
                      : 'text-[#9CA3AF] hover:bg-[#7C3AED]/10 hover:text-white'
                  }`}
                >
                  <Icon className="w-5 h-5 flex-shrink-0" />
                  {sidebarOpen && <span className="text-sm font-medium">{item.label}</span>}
                </button>
              </Link>
            );
          })}
        </nav>

        {/* Logout Button */}
        <div className="p-3 border-t border-[#7C3AED]/20">
          <button
            className="w-full flex items-center gap-3 px-4 py-3 rounded-lg text-[#9CA3AF] hover:bg-red-500/10 hover:text-red-400 transition-all duration-200"
          >
            <LogOut className="w-5 h-5 flex-shrink-0" />
            {sidebarOpen && <span className="text-sm font-medium">Logout</span>}
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden">
        {/* Top Bar */}
        <div className="h-16 bg-[#111111] border-b border-[#7C3AED]/20 flex items-center justify-between px-6">
          <h2 className="font-heading text-xl font-bold text-white">
            Administration Panel
          </h2>
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 rounded-full bg-[#7C3AED] flex items-center justify-center">
              <span className="text-sm font-bold">A</span>
            </div>
          </div>
        </div>

        {/* Content Area */}
        <div className="flex-1 overflow-auto bg-[#060606]">
          {children}
        </div>
      </main>
    </div>
  );
}

'use client';

import { useQuery } from '@tanstack/react-query';
import { Card } from '@mmorpg/ui';
import {
  Users,
  TrendingUp,
  Server,
  AlertCircle,
} from 'lucide-react';
import { DashboardMetrics } from '@/components/dashboard/dashboard-metrics';
import { SystemMetrics } from '@/components/dashboard/system-metrics';
import { RecentReports } from '@/components/dashboard/recent-reports';
import { PlayerActivityChart } from '@/components/dashboard/player-activity-chart';
import { LoadingSpinner } from '@/components/loading-spinner';

export default function AdminDashboard() {
  const { data: dashboardData, isLoading, error } = useQuery({
    queryKey: ['admin', 'dashboard'],
    queryFn: async () => {
      const response = await fetch('/api/admin/dashboard');
      if (!response.ok) throw new Error('Failed to fetch dashboard data');
      return response.json();
    },
    refetchInterval: 30000, // Refetch every 30 seconds
  });

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-full">
        <LoadingSpinner />
      </div>
    );
  }

  if (error) {
    return (
      <div className="p-6">
        <Card className="bg-red-500/10 border-red-500/30 p-6">
          <div className="flex items-center gap-3">
            <AlertCircle className="w-6 h-6 text-red-400" />
            <div>
              <h3 className="font-heading font-bold text-red-400">Error Loading Dashboard</h3>
              <p className="text-sm text-red-300 mt-1">
                Failed to load dashboard data. Please try refreshing the page.
              </p>
            </div>
          </div>
        </Card>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div>
        <h1 className="font-heading text-3xl font-bold text-white mb-2">
          Dashboard
        </h1>
        <p className="text-[#9CA3AF]">
          Welcome back, Admin. Here's an overview of your platform.
        </p>
      </div>

      {/* Key Metrics */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <DashboardMetrics
          title="Active Users (24h)"
          value={dashboardData?.activeUsers24h || 0}
          icon={Users}
          trend={12}
          color="primary"
        />
        <DashboardMetrics
          title="Total Users"
          value={dashboardData?.totalUsers || 0}
          icon={TrendingUp}
          trend={8}
          color="secondary"
        />
        <DashboardMetrics
          title="New Registrations (7d)"
          value={dashboardData?.newRegistrations7d || 0}
          icon={Users}
          trend={5}
          color="accent"
        />
        <DashboardMetrics
          title="Server Status"
          value={dashboardData?.serverStatus?.status === 'online' ? 'Online' : 'Offline'}
          icon={Server}
          status={dashboardData?.serverStatus?.status}
          color="success"
        />
      </div>

      {/* System Metrics and Recent Reports */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2">
          <SystemMetrics
            memoryUsage={dashboardData?.serverStatus?.memoryUsage}
            uptime={dashboardData?.serverStatus?.uptime}
          />
        </div>
        <div>
          <RecentReports />
        </div>
      </div>

      {/* Player Activity Chart */}
      <div>
        <PlayerActivityChart />
      </div>
    </div>
  );
}

